// Parse the research agent's output into a structured ResearchPacket
const researchRaw = $('Jurisdiction Research Agent').item.json.output || '';
const formData = $('Extract Form Data').item.json;

let researchPacket;
try {
  // Try to parse JSON from the output
  let jsonStr = researchRaw;
  // Strip markdown code fences if present
  jsonStr = jsonStr.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  // Find the first { and last }
  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }
  researchPacket = JSON.parse(jsonStr);
} catch (e) {
  // Fallback: wrap raw text in minimal ResearchPacket structure
  researchPacket = {
    researchSummary: researchRaw.substring(0, 3000),
    jurisdictionProfile: {
      country: formData.jurisdictionCountry || 'US',
      stateProvince: formData.jurisdictionState || '',
      city: formData.jurisdictionCity || '',
      authorityHierarchy: ['Federal', 'State', 'Local']
    },
    issuesIdentified: [formData.matterDescription?.substring(0, 200) || 'Legal matter'],
    applicableRules: [{
      ruleTitle: 'Research Findings',
      ruleType: 'statute',
      jurisdiction: formData.jurisdictionState || '',
      citationText: 'See research summary',
      sectionOrRule: 'N/A',
      summary: researchRaw.substring(0, 500),
      sourceUrl: '',
      sourceTitle: 'n8n Perplexity Research',
      relevance: 'Primary research',
      confidence: 'medium'
    }],
    localJurisdictionElements: [],
    factualDataNeeded: [],
    openQuestions: [],
    riskFlags: [],
    draftingConstraints: []
  };
}

// Ensure required fields exist with defaults
researchPacket.researchSummary = researchPacket.researchSummary || researchRaw.substring(0, 3000);
researchPacket.jurisdictionProfile = researchPacket.jurisdictionProfile || {
  country: formData.jurisdictionCountry || 'US',
  stateProvince: formData.jurisdictionState || '',
  city: formData.jurisdictionCity || '',
  authorityHierarchy: ['Federal', 'State', 'Local']
};
researchPacket.applicableRules = researchPacket.applicableRules || [];
researchPacket.riskFlags = researchPacket.riskFlags || [];
researchPacket.draftingConstraints = researchPacket.draftingConstraints || [];
researchPacket.issuesIdentified = researchPacket.issuesIdentified || [];
researchPacket.localJurisdictionElements = researchPacket.localJurisdictionElements || [];
researchPacket.factualDataNeeded = researchPacket.factualDataNeeded || [];
researchPacket.openQuestions = researchPacket.openQuestions || [];

return {
  json: {
    ...formData,
    researchPacket,
    researchRaw: researchRaw.substring(0, 5000)
  }
};

