={{ (function() {
  const fd = $json;
  const rp = fd.researchPacket || {};
  const rules = (rp.applicableRules || []).slice(0, 6);
  const cases = (rp.recentCasePrecedents || []).slice(0, 3);
  const sol = rp.statuteOfLimitations || {};
  const pre = rp.preSuitRequirements || {};
  const rem = rp.availableRemedies || {};
  const defs = (rp.commonDefenses || []).slice(0, 3);
  const enf = rp.enforcementClimate || {};

  const tone = fd.tonePreference || 'firm';
  const deadlineDays = tone === 'aggressive' ? 10 : tone === 'moderate' ? 21 : 14;

  let prompt = '## Matter Summary\n';
  prompt += 'Letter Type: ' + (fd.letterType || '').replace(/-/g, ' ').toUpperCase() + '\n';
  prompt += 'Tone Required: ' + tone.toUpperCase() + '\n';
  prompt += 'Response Deadline: ' + deadlineDays + ' days from today\n\n';

  prompt += '## Parties\nSENDER: ' + fd.senderName + ', ' + fd.senderAddress + '\n';
  if (fd.senderEmail) prompt += 'Email: ' + fd.senderEmail + '\n';
  if (fd.senderPhone) prompt += 'Phone: ' + fd.senderPhone + '\n';
  prompt += 'RECIPIENT: ' + fd.recipientName + ', ' + fd.recipientAddress + '\n\n';

  prompt += '## Jurisdiction\nState: ' + fd.jurisdictionState + '\nCountry: ' + fd.jurisdictionCountry + '\n';
  if (fd.jurisdictionCity) prompt += 'City: ' + fd.jurisdictionCity + '\n';
  prompt += '\n## Facts\n' + fd.matterDescription + '\n';
  if (fd.matterIncidentDate) prompt += 'Incident date: ' + fd.matterIncidentDate + '\n';
  if (fd.financialsAmount) prompt += 'Amount in dispute: $' + fd.financialsAmount + ' ' + fd.financialsCurrency + '\n';
  if (fd.desiredOutcome) prompt += 'Desired outcome: ' + fd.desiredOutcome + '\n';
  if (fd.additionalContext) prompt += 'Additional context: ' + fd.additionalContext + '\n';

  prompt += '\n---\n## Legal Foundation (from Research)\n';
  if (rules.length > 0) {
    prompt += '### Applicable Rules\n';
    rules.forEach(r => {
      prompt += '- [' + (r.ruleType || '').toUpperCase() + '] ' + r.ruleTitle + ' | ' + r.citationText + '\n  Summary: ' + r.summary + '\n  Relevance: ' + r.relevance + '\n\n';
    });
  }
  if (cases.length > 0) {
    prompt += '### Recent Precedents\n';
    cases.forEach(c => {
      prompt += '- ' + c.caseName + ' (' + c.citation + ') — ' + c.holding + '\n';
    });
    prompt += '\n';
  }
  if (sol.period) prompt += '### SOL: ' + sol.period + ' (' + sol.statute + ')\n\n';
  if (pre.demandLetterRequired) prompt += '### Pre-Suit: Demand letter required by ' + (pre.statute || 'statute') + '\n\n';
  if (rem.actualDamages) prompt += '### Remedies: ' + rem.actualDamages + '\n';
  if (rem.statutoryDamages) prompt += 'Statutory: ' + rem.statutoryDamages + '\n';
  if (rem.attorneyFees) prompt += 'Fees: ' + rem.attorneyFees + '\n\n';
  if (defs.length > 0) {
    prompt += '### Defenses to Pre-empt\n';
    defs.forEach(d => { prompt += '- ' + d.defense + ': ' + d.counterArgument + '\n'; });
    prompt += '\n';
  }
  prompt += '### Research Summary\n' + (rp.researchSummary || '').substring(0, 2000) + '\n';
  prompt += '### Risk Flags\n' + (rp.riskFlags || []).join('; ') + '\n';
  prompt += '### Drafting Constraints\n' + (rp.draftingConstraints || []).join('; ') + '\n';

  return prompt;
})() }}

