// Parse the drafting agent's output into structured DraftOutput
const draftRaw = $('Letter Drafting Agent').item.json.output || '';
const prevData = $('Parse Research Output').item.json;

let draftOutput;
try {
  let jsonStr = draftRaw;
  jsonStr = jsonStr.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }
  draftOutput = JSON.parse(jsonStr);
} catch (e) {
  // Fallback: treat raw text as the draft letter
  draftOutput = {
    draftLetter: draftRaw,
    attorneyReviewSummary: 'Draft generated by n8n pipeline. Please review carefully.',
    openQuestions: [],
    riskFlags: []
  };
}

// Ensure required fields
draftOutput.draftLetter = draftOutput.draftLetter || draftRaw;
draftOutput.attorneyReviewSummary = draftOutput.attorneyReviewSummary || '';
draftOutput.openQuestions = draftOutput.openQuestions || [];
draftOutput.riskFlags = draftOutput.riskFlags || [];

return {
  json: {
    ...prevData,
    draftOutput,
    draftRaw: draftRaw.substring(0, 5000)
  }
};

