// Build the structured callback payload matching the app's n8n-callback handler
const formData = $('Extract Form Data').item.json;
const parsedResearch = $('Parse Research Output').item.json;
const parsedDraft = $('Parse Draft Output').item.json;
const assemblyOutput = $('Assembly Stage (Claude)').item.json.output || '';

const researchPacket = parsedResearch.researchPacket || {};
const draftOutput = parsedDraft.draftOutput || {};

// Use the callbackUrl from the incoming payload, or fall back to variable
const callbackUrl = formData.callbackUrl || '';
const callbackSecret = formData.callbackSecret || $vars.INTERNAL_SECRET || '';

return {
  json: {
    letterId: parseInt(formData.letterId) || 0,
    success: true,
    // Structured data for the enhanced callback handler
    researchPacket: researchPacket,
    draftOutput: draftOutput,
    assembledLetter: assemblyOutput,
    // Legacy fields for backward compatibility
    draftContent: assemblyOutput || draftOutput.draftLetter || '',
    researchOutput: researchPacket.researchSummary || parsedResearch.researchRaw || '',
    // Metadata
    callbackUrl: callbackUrl,
    callbackSecret: callbackSecret,
    executionId: $execution.id,
    provider: 'n8n-3stage',
    stages: ['perplexity-research', 'anthropic-draft', 'anthropic-assembly']
  }
};
